#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int rowMask[9]={0}, colMask[9]={0}, boxMask[9]={0};
        bool ok=true;
        for(int i=0;i<9;i++){
            for(int j=0;j<9;j++){
                int v; scanf("%d", &v);
                if(v==0) continue;
                int bit = 1<<v;
                int b = (i/3)*3 + j/3;
                if(rowMask[i]&bit || colMask[j]&bit || boxMask[b]&bit){
                    ok=false;
                }
                rowMask[i]|=bit; colMask[j]|=bit; boxMask[b]|=bit;
            }
        }
        printf("%d\n", ok?1:0);
    }
    return 0;
}

