const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if (input.length === 0) process.exit(0);
const T = parseInt(input[idx++], 10);
let results = [];
for (let t = 0; t < T; t++) {
  const rowMask = Array(9).fill(0);
  const colMask = Array(9).fill(0);
  const boxMask = Array(9).fill(0);
  let ok = true;
  for (let i = 0; i < 9; i++) {
    for (let j = 0; j < 9; j++) {
      const v = parseInt(input[idx++], 10);
      if (v === 0) continue;
      const bit = 1 << v;
      const b = Math.floor(i / 3) * 3 + Math.floor(j / 3);
      if ((rowMask[i] & bit) || (colMask[j] & bit) || (boxMask[b] & bit)) ok = false;
      rowMask[i] |= bit;
      colMask[j] |= bit;
      boxMask[b] |= bit;
    }
  }
  results.push(ok ? '1' : '0');
}
console.log(results.join('\n'));
